export const Multiple = () => {
  type Item = {
    id: number;
    title: string;
    value: string;
    trend: number;
  };
  const [data, setData] = React.useState<Item[]>([
    { id: 1, title: '销售额', value: '¥1000000', trend: 15 },
    { id: 2, title: '订单量', value: '¥2000000', trend: -5 },
    { id: 3, title: '用户数', value: '¥3000000', trend: 20 },
    { id: 4, title: '转化率', value: '¥4000000', trend: 8 },
    {
      id: 5,
      title: '超长标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题标题',
      value: '¥5000000',
      trend: -12,
    },
  ]);
  const [editingItem, setEditingItem] = React.useState<Item | null>(null);
  const [editValue, setEditValue] = React.useState('');

  const handleAdd = () => {
    const newItem = {
      id: Date.now(),
      title: '新指标',
      value: '¥0',
      trend: 0,
    };
    setData([...data, newItem]);
  };

  const handleDelete = (id: number) => {
    setData(data.filter(item => item.id !== id));
  };

  const handleEdit = (item: Item | null) => {
    setEditingItem(item);
    setEditValue(item!.title); // 修改为编辑 title
  };

  const handleSave = () => {
    if (!editingItem) {
      return;
    }
    setData(
      data.map(item =>
        item.id === editingItem.id
          ? { ...item, title: editValue } // 修改为保存 title
          : item,
      ),
    );
    setEditingItem(null);
  };

  return (
    <div>
      <Button onClick={handleAdd}>添加指标</Button>
      <div style={{ width: '900px' }}>
        <MetricsGroup>
          {data.map(item => (
            <Card key={item.id} style={{ width: '300px', display: 'inline-block', verticalAlign: 'top' }}>
              <Metrics
                mainTitle={
                  item.id === editingItem?.id ? (
                    <Input
                      value={editValue}
                      onChange={e => setEditValue(e.target.value)}
                      onBlur={handleSave}
                      onPressEnter={handleSave}
                      autoFocus
                    />
                  ) : (
                    item.title
                  )
                }
                mainValue={item.value}
                secondary={{
                  data: [
                    {
                      type: item.trend > 0 ? 'increase' : 'decrease',
                      label: '环比',
                      value: `${Math.abs(item.trend)}%`,
                      color: item.trend > 0 ? 'danger' : 'success',
                    },
                  ],
                }}
                footer={
                  <div style={{ textAlign: 'right' }}>
                    <Button onClick={() => handleEdit(item)} style={{ marginRight: '8px' }}>
                      编辑标题
                    </Button>
                    <Button onClick={() => handleDelete(item.id)}>删除</Button>
                  </div>
                }
              />
            </Card>
          ))}
        </MetricsGroup>
      </div>
    </div>
  );
};

export const Layout = () => {
  const [enableGroup, setEnableGroup] = React.useState(true);

  const Comp = enableGroup ? MetricsGroup : React.Fragment;

  return (
    <div
      style={{
        width: '900px',
      }}
    >
      <div>
        <Button
          onClick={() => {
            setEnableGroup(!enableGroup);
          }}
        >
          {enableGroup ? '禁用分组' : '启用分组'}
        </Button>
      </div>
      <Comp>
        <PerformanceContent componentName="SeveralMetrics" count={100} itemRenderer={() => <SeveralMetrics />} />
      </Comp>
    </div>
  );
};

